1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty grid when given empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with 0 neighbors", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should preserve a 2x2 block (still life - each cell has 3 neighbors)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
18	      new Set(["0,0", "1,0", "0,1", "1,1"]),
19	    );
20	  });
21	  it.todo("should rotate a vertical blinker into a horizontal blinker");
22	  it.todo("should bring a dead cell with exactly 3 live neighbors to life");
23	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
24	  it.todo("should support negative coordinates");
25	});
26

1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number => {
6	  let count = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (liveSet.has(cellKey(x + dx, y + dy))) count++;
11	    }
12	  }
13	  return count;
14	};
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
18	
19	  return cells.filter(([x, y]) => {
20	    const neighbors = countLiveNeighbors(x, y, liveSet);
21	    return neighbors === 2 || neighbors === 3;
22	  });
23	}
